import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 13: Safety and Permissions","description":"Designing robust safety systems and permission architectures for coding agents that operate on real codebases.","frontmatter":{"title":"Chapter 13: Safety and Permissions","description":"Designing robust safety systems and permission architectures for coding agents that operate on real codebases."},"headers":[],"relativePath":"learn/linear/13-safety-and-permissions/index.md","filePath":"learn/linear/13-safety-and-permissions/index.md"}'),n={name:"learn/linear/13-safety-and-permissions/index.md"};function r(l,e,o,d,h,c){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="safety-and-permissions" tabindex="-1">Safety and Permissions <a class="header-anchor" href="#safety-and-permissions" aria-label="Permalink to &quot;Safety and Permissions&quot;">​</a></h1><p>Coding agents wield real power: they read files, write code, execute commands, and interact with external services. With that power comes serious risk. A misconfigured agent can delete files, leak secrets, run destructive commands, or silently introduce vulnerabilities into a codebase. This chapter tackles the problem of making agents safe by design rather than safe by luck.</p><p>We begin with threat modeling specific to coding agents, identifying the unique attack surfaces and failure modes that arise when an LLM drives a development workflow. From there, we build layered permission architectures that control what an agent can do, approval flows that keep a human in the loop for dangerous operations, and checkpoint/rollback systems that let you undo mistakes. We also explore sandboxing techniques that contain blast radius when things go wrong.</p><p>The chapter culminates with audit trails, rate limiting, and comprehensive testing strategies for safety systems. You will learn not just how to build these systems, but how to verify they actually work under adversarial conditions. Every safety mechanism we design follows a defense-in-depth philosophy: no single layer is trusted to catch every problem.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Identify and categorize threats specific to LLM-powered coding agents</li><li>Design multi-layered permission architectures with allowlists, denylists, and capability scoping</li><li>Implement human-in-the-loop approval flows for high-risk operations</li><li>Build checkpoint and rollback systems that enable safe recovery from agent errors</li><li>Apply sandboxing techniques to limit the blast radius of agent actions</li><li>Construct audit trails and rate limiting systems for operational visibility</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/13-safety-and-permissions/01-threat-modeling.html">Threat Modeling</a></li><li><a href="/linear/13-safety-and-permissions/02-permission-architectures.html">Permission Architectures</a></li><li><a href="/linear/13-safety-and-permissions/03-approval-flows.html">Approval Flows</a></li><li><a href="/linear/13-safety-and-permissions/04-checkpoint-systems.html">Checkpoint Systems</a></li><li><a href="/linear/13-safety-and-permissions/05-rollback-mechanisms.html">Rollback Mechanisms</a></li><li><a href="/linear/13-safety-and-permissions/06-allowlist-denylist-design.html">Allowlist Denylist Design</a></li><li><a href="/linear/13-safety-and-permissions/07-sandboxing-deep-dive.html">Sandboxing Deep Dive</a></li><li><a href="/linear/13-safety-and-permissions/08-plan-mode-design.html">Plan Mode Design</a></li><li><a href="/linear/13-safety-and-permissions/09-audit-trails.html">Audit Trails</a></li><li><a href="/linear/13-safety-and-permissions/10-rate-limiting-agents.html">Rate Limiting Agents</a></li><li><a href="/linear/13-safety-and-permissions/11-testing-safety-systems.html">Testing Safety Systems</a></li><li><a href="/linear/13-safety-and-permissions/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 7 (process management and sandboxing fundamentals)</li><li>Chapter 12 (git operations for checkpointing and rollback)</li></ul>',10)])])}const f=a(n,[["render",r]]);export{p as __pageData,f as default};
